654→/** Log a git commit to the graph */
655→export async function logCommit(input: {
656→  surreal: Surreal;
657→  workspaceRecord: RecordId<"workspace", string>;
658→  projectRecord?: RecordId<"project", string>;
659→  sha: string;
660→  message: string;
661→  author: string;
662→  taskUpdates?: Array<{ task_id: string; new_status: string }>;
663→  relatedTaskIds?: string[];
664→  decisionsDetected?: Array<{ name: string; rationale: string }>;
665→}): Promise<{ commit_id: string; tasks_updated: number; tasks_linked: number; decisions_created: number }> {
666→  const now = new Date();
667→  const commitRecord = new RecordId("git_commit", randomUUID());
668→
669→  await input.surreal.create(commitRecord).content({
670→    sha: input.sha,
671→    message: input.message,
672→    author_name: input.author,
673→    workspace: input.workspaceRecord,
674→    authored_at: now,
675→    created_at: now,
676→  });
677→
678→  // Update task statuses
679→  let tasksUpdated = 0;
680→  if (input.taskUpdates?.length) {
681→    for (const update of input.taskUpdates) {
682→      const taskRecord = new RecordId("task", requireRawId(update.task_id, "task_updates[].task_id"));
683→      const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
684→      if (!task) {
685→        throw new Error(`task not found: ${update.task_id}`);
686→      }
687→      if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
688→        throw new Error("task update is outside the current workspace scope");
689→      }
690→      await input.surreal.update(taskRecord).merge({
691→        status: update.new_status,
692→        updated_at: now,
693→      });
694→      tasksUpdated++;
695→    }
696→  }
697→
698→  // Link related tasks to this commit
699→  const linkedTaskIds = new Set<string>();
700→  // Include tasks from task_updates
701→  if (input.taskUpdates?.length) {
702→    for (const update of input.taskUpdates) {
703→      linkedTaskIds.add(requireRawId(update.task_id, "task_updates[].task_id"));
704→    }
705→  }
706→  // Include explicitly declared related tasks
707→  if (input.relatedTaskIds?.length) {
708→    for (const taskId of input.relatedTaskIds) {
709→      linkedTaskIds.add(requireRawId(taskId, "related_task_ids[]"));
710→    }
711→  }
712→  for (const taskId of linkedTaskIds) {
713→    const taskRecord = new RecordId("task", taskId);
714→    const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
715→    if (!task) {
716→      throw new Error(`task not found: ${taskId}`);
717→    }
718→    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
719→      throw new Error("task link is outside the current workspace scope");
720→    }
721→    await input.surreal
722→      .relate(taskRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
723→        commit_sha: input.sha,
724→        linked_at: now,
725→      })
726→      .output("after");
727→  }
728→
729→  // Create provisional decisions if flagged
730→  let decisionsCreated = 0;
731→  if (input.decisionsDetected?.length) {
732→    for (const decision of input.decisionsDetected) {
733→      const decisionRecord = new RecordId("decision", randomUUID());
734→      await input.surreal.create(decisionRecord).content({
735→        summary: decision.name,
736→        rationale: decision.rationale,
737→        status: "provisional",
738→        decided_by_name: "code-agent",
739→        workspace: input.workspaceRecord,
740→        source_commit: commitRecord,
741→        created_at: now,
742→        updated_at: now,
743→      });
744→
745→      // Link decision to project (if known)
746→      if (input.projectRecord) {
747→        await input.surreal
748→          .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
749→            added_at: now,
750→          })
751→          .output("after");
752→      }
753→
754→      // Create implemented_by edge
755→      await input.surreal
756→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
757→          commit_sha: input.sha,
758→          linked_at: now,
759→        })
760→        .output("after");
761→
762→      decisionsCreated++;
763→    }
764→  }
765→
766→  return {
767→    commit_id: toRawId(commitRecord),
768→    tasks_updated: tasksUpdated,
769→    tasks_linked: linkedTaskIds.size,
770→    decisions_created: decisionsCreated,
771→  };
772→}
