854→// ---------------------------------------------------------------------------
855→// Utility
856→// ---------------------------------------------------------------------------
857→
858→function levenshteinSimilarity(a: string, b: string): number {
859→  if (a === b) return 1;
860→  const longer = a.length > b.length ? a : b;
861→  const shorter = a.length > b.length ? b : a;
862→  if (longer.length === 0) return 1;
863→
864→  const costs: number[] = [];
865→  for (let i = 0; i <= longer.length; i++) {
866→    let lastValue = i;
867→    for (let j = 0; j <= shorter.length; j++) {
868→      if (i === 0) {
869→        costs[j] = j;
870→      } else if (j > 0) {
871→        let newValue = costs[j - 1];
872→        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
873→          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
874→        }
875→        costs[j - 1] = lastValue;
876→        lastValue = newValue;
877→      }
878→    }
879→    if (i > 0) costs[shorter.length] = lastValue;
880→  }
881→
882→  return (longer.length - costs[shorter.length]) / longer.length;
883→}
