36→/**
37→ * Process a commit message to extract task references and transition
38→ * matched tasks to "done".
39→ *
40→ * Pipeline:
41→ *   commitMessage -> extractReferencedTaskIds (regex) -> filter existing -> updateTask each -> results
42→ */
43→export async function processCommitTaskRefs(
44→  input: CommitCheckInput,
45→): Promise<CommitCheckResult> {
46→  const taskIds = extractReferencedTaskIds(input.commitMessage);
47→
48→  if (taskIds.length === 0) {
49→    return { updatedTasks: [] };
50→  }
51→
52→  // Filter to only tasks that exist in this workspace
53→  const existenceChecks = await Promise.all(
54→    taskIds.map(async (id) => ({ id, exists: await input.taskExists(id) })),
55→  );
56→  const existingTaskIds = existenceChecks
57→    .filter((check) => check.exists)
58→    .map((check) => check.id);
59→
60→  if (existingTaskIds.length === 0) {
61→    return { updatedTasks: [] };
62→  }
63→
64→  // Update each task to "done"
65→  const updatedTasks = await Promise.all(
66→    existingTaskIds.map((taskId) => input.updateTask(taskId, "done")),
67→  );
68→
69→  return { updatedTasks };
70→}
